{
  "name": "SceneScribe: AI Storyboard Director",
  "description": "A cinematic storyboard generator that transforms any story into a sequence of visually stunning, professionally directed frames using Gemini AI.",
  "requestFramePermissions": []
}

export interface Scene {
  number: number;
  description: string;
  shotType: string;
  movement: string;
  lighting: string;
  tone: string;
  prompt: string;
}

export interface StoryboardResponse {
  scenes: Scene[];
}

export type AppStatus = 'idle' | 'analyzing' | 'visualizing' | 'completed' | 'error';

import { GoogleGenAI, Type } from "@google/genai";
import { Scene, StoryboardResponse } from "./types";

export const generateStoryboardData = async (story: string): Promise<StoryboardResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Act as a Hollywood storyboard director. Analyze this story and break it down into exactly 6-8 cinematic scenes: "${story}".

    For each scene, provide:
    1. Scene Number
    2. Visual Frame Description (detailed cinematic composition)
    3. Camera Shot Type
    4. Camera Movement
    5. Lighting Style
    6. Emotional Tone
    7. AI Image Prompt (highly detailed, 4K cinematic film still, consistent character descriptions)

    IMPORTANT: Ensure consistent character appearance (hair, outfit, age) in the AI Image Prompts.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          scenes: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                number: { type: Type.INTEGER },
                description: { type: Type.STRING },
                shotType: { type: Type.STRING },
                movement: { type: Type.STRING },
                lighting: { type: Type.STRING },
                tone: { type: Type.STRING },
                prompt: { type: Type.STRING },
              },
              required: ["number", "description", "shotType", "movement", "lighting", "tone", "prompt"],
            },
          },
        },
        required: ["scenes"],
      },
    },
  });

  const jsonStr = response.text.trim();
  return JSON.parse(jsonStr) as StoryboardResponse;
};

export const generateSceneImage = async (prompt: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        {
          text: `Professional Hollywood cinematic storyboard frame: ${prompt}. Ultra-realistic, 4K, depth of field, sharp focus, high-end color grading.`,
        },
      ],
    },
    config: {
      imageConfig: {
        aspectRatio: "16:9",
      },
    },
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }

  throw new Error("No image data found in response");
};

