import React, { useState, useCallback } from 'react';
import { Scene, AppStatus } from './types';
import { generateStoryboardData, generateSceneImage } from './geminiService';
import { SceneCard } from './components/SceneCard';
import { Film, Clapperboard, Sparkles, Send, Trash2, ChevronRight, AlertCircle } from 'lucide-react';

const App: React.FC = () => {
  const [story, setStory] = useState('');
  const [scenes, setScenes] = useState<Scene[]>([]);
  const [images, setImages] = useState<Record<number, string>>({});
  const [status, setStatus] = useState<AppStatus>('idle');
  const [error, setError] = useState<string | null>(null);
  const [generatingImageIndices, setGeneratingImageIndices] = useState<Set<number>>(new Set());

  const handleGenerate = async () => {
    if (!story.trim()) return;

    setStatus('analyzing');
    setError(null);
    setScenes([]);
    setImages({});
    setGeneratingImageIndices(new Set());

    try {
      const data = await generateStoryboardData(story);
      setScenes(data.scenes);
      setStatus('visualizing');

      // Generate images one by one for visual feedback
      for (const scene of data.scenes) {
        setGeneratingImageIndices(prev => new Set(Array.from(prev).concat(scene.number)));
        try {
          const imageUrl = await generateSceneImage(scene.prompt);
          setImages(prev => ({ ...prev, [scene.number]: imageUrl }));
        } catch (imgErr) {
          console.error(`Failed to generate image for scene ${scene.number}`, imgErr);
        } finally {
          setGeneratingImageIndices(prev => {
            const next = new Set(prev);
            next.delete(scene.number);
            return next;
          });
        }
      }
      setStatus('completed');
    } catch (err: any) {
      console.error(err);
      setError(err.message || 'An error occurred during generation.');
      setStatus('error');
    }
  };

  const handleClear = () => {
    setStory('');
    setScenes([]);
    setImages({});
    setStatus('idle');
    setError(null);
  };

  const loadExample = () => {
    setStory("In a rain-soaked cyberpunk Tokyo, a weary detective named Kael, wearing a high-collared trench coat, discovers a glowing blue data cube in a deserted alleyway. As he touches it, a hologram of a lost child flickers to life, begging for help. Kael looks up as a swarm of surveillance drones descends from the neon-lit clouds. He runs through the crowded night market, knocking over stalls of synth-noodles, until he reaches the edge of the floating harbor. He looks back at the approaching drones and leaps into the dark abyss of the lower city.");
  };

  return (
    <div className="min-h-screen flex flex-col pb-20">
      {/* Header */}
      <header className="sticky top-0 z-50 bg-slate-950/80 backdrop-blur-xl border-b border-slate-800">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-1.5 rounded-lg shadow-lg shadow-indigo-500/20">
              <Clapperboard className="w-5 h-5 text-white" />
            </div>
            <h1 className="text-xl font-bold tracking-tight text-white">SceneScribe</h1>
          </div>

          <div className="hidden md:flex items-center gap-6 text-xs font-semibold text-slate-400 uppercase tracking-widest">
            <span className="hover:text-indigo-400 cursor-pointer">Director's Room</span>
            <span className="hover:text-indigo-400 cursor-pointer">Archive</span>
            <span className="hover:text-indigo-400 cursor-pointer">Tutorials</span>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-7xl mx-auto px-4 py-12 w-full">
        <div className="max-w-3xl mx-auto text-center mb-12">
          <h2 className="text-4xl md:text-5xl font-serif mb-4 text-white">Bring Your Vision to Life</h2>
          <p className="text-slate-400 text-lg">Input your script or story and let our AI Director craft a professional cinematic storyboard sequence.</p>
        </div>

        {/* Story Input Section */}
        <div className="max-w-4xl mx-auto mb-16">
          <div className="bg-slate-900 border border-slate-800 rounded-2xl p-1 shadow-2xl">
            <div className="relative">
              <textarea
                value={story}
                onChange={(e) => setStory(e.target.value)}
                placeholder="Once upon a time in a galaxy far away..."
                className="w-full bg-slate-950 text-slate-200 border-0 rounded-xl p-6 min-h-[200px] focus:ring-2 focus:ring-indigo-500/50 resize-none placeholder:text-slate-600 text-lg leading-relaxed"
              />
              {status === 'idle' && story === '' && (
                <button 
                  onClick={loadExample}
                  className="absolute bottom-6 left-6 text-indigo-400 text-sm font-medium hover:text-indigo-300 transition-colors flex items-center gap-1"
                >
                  <Sparkles className="w-4 h-4" />
                  Try an example
                </button>
              )}
            </div>

            <div className="p-4 flex flex-col md:flex-row gap-4 items-center justify-between border-t border-slate-800 bg-slate-900/50 rounded-b-xl">
              <div className="flex items-center gap-2 text-slate-500 text-sm">
                <Film className="w-4 h-4" />
                <span>AI will generate 6-8 frames with technical metadata</span>
              </div>

              <div className="flex items-center gap-3 w-full md:w-auto">
                <button
                  onClick={handleClear}
                  className="px-6 py-3 rounded-xl border border-slate-700 text-slate-400 hover:bg-slate-800 transition-all active:scale-95 flex items-center gap-2 flex-1 md:flex-initial justify-center"
                >
                  <Trash2 className="w-4 h-4" />
                  Clear
                </button>
                <button
                  onClick={handleGenerate}
                  disabled={status === 'analyzing' || status === 'visualizing' || !story.trim()}
                  className="px-8 py-3 rounded-xl bg-indigo-600 hover:bg-indigo-500 text-white font-bold shadow-lg shadow-indigo-600/20 transition-all hover:translate-y-[-2px] active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2 flex-1 md:flex-initial justify-center"
                >
                  {status === 'analyzing' ? (
                    <>
                      <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                      Analyzing...
                    </>
                  ) : status === 'visualizing' ? (
                    <>
                      <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                      Visualizing...
                    </>
                  ) : (
                    <>
                      <Send className="w-4 h-4" />
                      Generate Storyboard
                    </>
                  )}
                </button>
              </div>
            </div>
          </div>
        </div>

        {error && (
          <div className="max-w-4xl mx-auto mb-8 bg-rose-500/10 border border-rose-500/20 p-4 rounded-xl flex items-center gap-3 text-rose-400">
            <AlertCircle className="w-5 h-5 shrink-0" />
            <p className="text-sm">{error}</p>
          </div>
        )}

        {/* Storyboard Display */}
        {scenes.length > 0 && (
          <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="flex items-center justify-between border-b border-slate-800 pb-6">
              <div>
                <h3 className="text-2xl font-bold text-white flex items-center gap-3">
                  Storyboard Sequence
                  {status === 'visualizing' && (
                    <span className="text-xs bg-indigo-500/20 text-indigo-400 px-2 py-1 rounded-full animate-pulse uppercase tracking-widest font-bold">In Production</span>
                  )}
                </h3>
                <p className="text-slate-500 text-sm mt-1">{scenes.length} frames directed by AI</p>
              </div>
              <div className="flex gap-1">
                {scenes.map((_, i) => (
                  <div 
                    key={i} 
                    className={`h-1 w-8 rounded-full transition-colors ${i < Object.keys(images).length ? 'bg-indigo-500' : 'bg-slate-800'}`} 
                  />
                ))}
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-2 gap-8">
              {scenes.map((scene) => (
                <SceneCard 
                  key={scene.number} 
                  scene={scene} 
                  imageUrl={images[scene.number]}
                  isGeneratingImage={generatingImageIndices.has(scene.number)}
                />
              ))}
            </div>

            {status === 'completed' && (
              <div className="text-center pt-12">
                <button className="px-10 py-4 bg-white text-slate-950 font-bold rounded-2xl hover:bg-slate-200 transition-all flex items-center gap-2 mx-auto shadow-2xl">
                  Export Board as PDF
                  <ChevronRight className="w-4 h-4" />
                </button>
              </div>
            )}
          </div>
        )}
      </main>

      {/* Footer */}
      <footer className="mt-auto border-t border-slate-900 py-10">
        <div className="max-w-7xl mx-auto px-4 text-center">
          <p className="text-slate-600 text-sm">© 2024 SceneScribe AI • Built for Modern Storytelling</p>
        </div>
      </footer>
    </div>
  );
};

export default App;

