export interface Scene {
  number: number;
  description: string;
  shotType: string;
  movement: string;
  lighting: string;
  tone: string;
  prompt: string;
}

export interface StoryboardResponse {
  characterProfile: string;
  scenes: Scene[];
}

export type AppStatus = 'idle' | 'analyzing' | 'visualizing' | 'completed' | 'error';

import { GoogleGenAI, Type } from "@google/genai";
import { Scene, StoryboardResponse } from "./types";

export const generateStoryboardData = async (story: string): Promise<StoryboardResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Act as a Hollywood storyboard director. 
    Analyze this story: "${story}".

    STEP 1: Identify the main character and create a fixed, detailed visual description (age, hair, specific outfit, facial features). This is the CHARACTER PROFILE.
    STEP 2: Break the story into a sequence of scenes naturally based on story flow.
    STEP 3: For each scene, generate technical storyboard data. 

    IMPORTANT: Every "prompt" MUST start with the exact CHARACTER PROFILE description followed by the scene action to maintain strict visual consistency.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          characterProfile: { 
            type: Type.STRING,
            description: "A detailed visual description of the protagonist used to maintain consistency."
          },
          scenes: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                number: { type: Type.INTEGER },
                description: { type: Type.STRING },
                shotType: { type: Type.STRING },
                movement: { type: Type.STRING },
                lighting: { type: Type.STRING },
                tone: { type: Type.STRING },
                prompt: { 
                  type: Type.STRING,
                  description: "Full AI prompt starting with character description followed by scene context."
                },
              },
              required: ["number", "description", "shotType", "movement", "lighting", "tone", "prompt"],
            },
          },
        },
        required: ["characterProfile", "scenes"],
      },
    },
  });

  const jsonStr = response.text.trim();
  return JSON.parse(jsonStr) as StoryboardResponse;
};

export const generateSceneImage = async (prompt: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        {
          text: `Professional Hollywood cinematic storyboard film still, 35mm film, high quality. ${prompt}. Detailed environment, sharp focus, professional color grading, depth of field.`,
        },
      ],
    },
    config: {
      imageConfig: {
        aspectRatio: "16:9",
      },
    },
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }

  throw new Error("No image data found in response");
};

