import { GoogleGenAI, Type } from "@google/genai";
import { Scene, StoryboardResponse } from "./types";

export const generateStoryboardData = async (story: string): Promise<StoryboardResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Act as a master Hollywood storyboard director and visual consultant. 
    Analyze this story: "${story}".

    STEP 1: Define a high-fidelity CHARACTER PROFILE for the protagonist. Include age, specific facial features (eye shape, nose, jawline), hair texture/style, and a very detailed outfit (fabrics, colors, wear-and-tear). This profile will be the anchor for consistency.

    STEP 2: Break the story into cinematic beats. For each beat, define the CHARACTER'S EMOTIONAL STATE (e.g., "eyes wide with terror," "a subtle, confident smirk," "brow furrowed in deep concentration").

    STEP 3: For each scene, generate technical storyboard data. 

    CRITICAL INSTRUCTIONS FOR PROMPTS:
    - Every "prompt" MUST start with the exact CHARACTER PROFILE.
    - Immediately follow with the specific FACIAL EXPRESSION and BODY LANGUAGE for that exact moment.
    - Describe the lighting and atmosphere to ensure the "shot" looks like a real film production.
    - Ensure the character looks identical but reacts authentically to the scene's events.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          characterProfile: { 
            type: Type.STRING,
            description: "A detailed physical and wardrobe description of the protagonist."
          },
          scenes: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                number: { type: Type.INTEGER },
                description: { type: Type.STRING },
                shotType: { type: Type.STRING },
                movement: { type: Type.STRING },
                lighting: { type: Type.STRING },
                tone: { type: Type.STRING },
                prompt: { 
                  type: Type.STRING,
                  description: "Full AI prompt: [Character Profile] + [Current Facial Expression/Reaction] + [Action/Environment]."
                },
              },
              required: ["number", "description", "shotType", "movement", "lighting", "tone", "prompt"],
            },
          },
        },
        required: ["characterProfile", "scenes"],
      },
    },
  });

  const jsonStr = response.text.trim();
  return JSON.parse(jsonStr) as StoryboardResponse;
};

export const generateSceneImage = async (prompt: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Using high-end cinematic keywords for photorealism
  const enhancedPrompt = `A hyper-realistic cinematic film still, shot on Arri Alexa with master prime lenses. ${prompt}. 8k resolution, photorealistic skin textures, naturalistic lighting, anamorphic lens flares, slight film grain, professional color grading, sharp focus on subject, shallow depth of field.`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        {
          text: enhancedPrompt,
        },
      ],
    },
    config: {
      imageConfig: {
        aspectRatio: "16:9",
      },
    },
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }

  throw new Error("No image data found in response");
};

