import { GoogleGenAI, Type } from "@google/genai";
import { Scene, StoryboardResponse } from "./types";

export const generateStoryboardData = async (story: string): Promise<StoryboardResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Act as a world-class Cinematic Storyboard Artist. Your absolute priority is STRICT CHARACTER CONSISTENCY, specifically the protagonist's face.

    STEP 1: Define a "FIXED VISUAL IDENTITY" (The Character Bible). 
    Create a highly detailed 4-line description that acts as a visual anchor. 
    It MUST include:
    - FACE ANCHOR: Unique identifiable facial features (bone structure, eye shape/color, nose profile, specific jawline).
    - HAIR & AGE: Specific hair texture, color, cut, and age.
    - WARDROBE: A unique, consistent outfit (materials, colors, specific layers).
    This block will be the first part of EVERY image prompt to ensure the face never drifts.

    STEP 2: Analyze the story flow: "${story}".
    Break it down into logical cinematic beats.

    STEP 3: For each scene, create:
    - Scene Number
    - Visual Description
    - Technical specs (Shot type, camera movement, lighting, mood)
    - FACIAL EXPRESSION: Define how the character's specific face (from Step 1) reacts (e.g., "eyes squinting in focus," "mouth agape in terror").

    STEP 4: Generate the "PROMPT". 
    MANDATORY STRUCTURE: [FIXED VISUAL IDENTITY] + [CURRENT FACIAL EXPRESSION] + [ACTION & ENVIRONMENT].

    The character must look like the same actor in every frame, just with different expressions and in different lighting.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          characterProfile: { 
            type: Type.STRING,
            description: "The 'Character Bible' block used for face and body consistency."
          },
          scenes: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                number: { type: Type.INTEGER },
                description: { type: Type.STRING },
                shotType: { type: Type.STRING },
                movement: { type: Type.STRING },
                lighting: { type: Type.STRING },
                tone: { type: Type.STRING },
                prompt: { 
                  type: Type.STRING,
                  description: "Final prompt starting with the Fixed Visual Identity for absolute consistency."
                },
              },
              required: ["number", "description", "shotType", "movement", "lighting", "tone", "prompt"],
            },
          },
        },
        required: ["characterProfile", "scenes"],
      },
    },
  });

  const jsonStr = response.text.trim();
  return JSON.parse(jsonStr) as StoryboardResponse;
};

export const generateSceneImage = async (prompt: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // High-weighting for character consistency and photorealistic film still
  const enhancedPrompt = `A high-end cinematic film still, extreme photorealism, shot on 35mm Arri Alexa. Focus on character consistency: ${prompt}. Professional cinematography, high-fidelity facial textures, pore details, realistic eyes with reflections, authentic lighting, subtle film grain, masterfully color graded, sharp focus, 8k.`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        {
          text: enhancedPrompt,
        },
      ],
    },
    config: {
      imageConfig: {
        aspectRatio: "16:9",
      },
    },
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }

  throw new Error("No image data found in response");
};

