/**
 * Generates an image with retry logic for 429 Resource Exhausted errors.
 */
export const generateSceneImage = async (prompt: string, retries = 3): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const enhancedPrompt = `A high-end cinematic film still, extreme photorealism, shot on 35mm Arri Alexa. Focus on character consistency: ${prompt}. Professional cinematography, high-fidelity facial textures, pore details, realistic eyes with reflections, authentic lighting, subtle film grain, masterfully color graded, sharp focus, 8k.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: enhancedPrompt }],
      },
      config: {
        imageConfig: {
          aspectRatio: "16:9",
        },
      },
    });

    const part = response.candidates?.[0]?.content?.parts?.find(p => p.inlineData);
    if (part?.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
    throw new Error("No image data found in response");
  } catch (error: any) {
    if (retries > 0 && (error.message?.includes("429") || error.status === 429 || error.message?.includes("quota"))) {
      const waitTime = Math.pow(2, 4 - retries) * 2000; // Exponential backoff: 2s, 4s, 8s
      console.warn(`Quota exceeded. Retrying in ${waitTime}ms... (${retries} retries left)`);
      await delay(waitTime);
      return generateSceneImage(prompt, retries - 1);
    }
    throw error;
  }
};

