import { GoogleGenAI, Type } from "@google/genai";
import { Scene, StoryboardResponse } from "./types";

const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export const generateStoryboardData = async (story: string): Promise<StoryboardResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Act as a world-class Cinematic Visual Storyteller and Director of Photography. 
    Your primary objective is to maintain ABSOLUTE CHARACTER CONSISTENCY across a sequence of film stills.

    STEP 1: Define a "MASTER IDENTITY ANCHOR". 
    Create a 6-line technical visual description of the protagonist that will be used verbatim as the prefix for every image.
    It MUST be highly specific:
    - FACIAL TOPOLOGY: Exact bone structure (e.g., "high angular cheekbones", "heavy brow ridge"), eye shape and unique color (e.g., "narrow almond-shaped piercing amber eyes"), nose profile (e.g., "straight aquiline nose"), and mouth shape.
    - SKIN & DETAILS: Specific skin texture, unique identifiers (e.g., "a faint vertical scar through the left eyebrow"), and age.
    - COIFFURE: Exact hair length, texture, and styling (e.g., "tightly cropped obsidian buzz cut with a sharp fade").
    - WARDROBE: A signature outfit that remains constant (e.g., "a weathered charcoal wool greatcoat with tarnished silver buttons over a black ribbed turtleneck").

    STEP 2: Analyze the story beats: "${story}".

    STEP 3: For each scene, create a specific emotional micro-expression that modifies the MASTER IDENTITY but does not alter the underlying facial structure.

    STEP 4: Output JSON. The "prompt" field for each scene MUST strictly follow this pattern:
    [MASTER IDENTITY ANCHOR] + [MICRO-EXPRESSION & FACIAL REACTION] + [CINEMATIC SHOT SPECS & ENVIRONMENT].`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          characterProfile: { 
            type: Type.STRING,
            description: "The technical 'Master Identity Anchor' for the character."
          },
          scenes: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                number: { type: Type.INTEGER },
                description: { type: Type.STRING },
                shotType: { type: Type.STRING },
                movement: { type: Type.STRING },
                lighting: { type: Type.STRING },
                tone: { type: Type.STRING },
                prompt: { 
                  type: Type.STRING,
                  description: "Full prompt starting with the Master Identity Anchor."
                },
              },
              required: ["number", "description", "shotType", "movement", "lighting", "tone", "prompt"],
            },
          },
        },
        required: ["characterProfile", "scenes"],
      },
    },
  });

  const jsonStr = response.text.trim();
  return JSON.parse(jsonStr) as StoryboardResponse;
};

export const generateSceneImage = async (prompt: string, retries = 3): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // High-fidelity cinematic injection
  const enhancedPrompt = `Photorealistic cinematic film still, shot on 35mm film, Arri Alexa. THE CHARACTER FACE MUST BE IDENTICAL TO PREVIOUS FRAMES: ${prompt}. Authentic skin pores, realistic tear ducts, sharp eye focus with catchlights, Hollywood lighting, depth of field, 8k, masterfully color graded, high character consistency, movie production quality.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: enhancedPrompt }],
      },
      config: {
        imageConfig: {
          aspectRatio: "16:9",
        },
      },
    });

    const part = response.candidates?.[0]?.content?.parts?.find(p => p.inlineData);
    if (part?.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
    throw new Error("No image data found in response");
  } catch (error: any) {
    if (retries > 0 && (error.message?.includes("429") || error.status === 429 || error.message?.includes("quota"))) {
      const waitTime = Math.pow(2, 4 - retries) * 2000;
      console.warn(`Quota exceeded. Retrying in ${waitTime}ms... (${retries} retries left)`);
      await delay(waitTime);
      return generateSceneImage(prompt, retries - 1);
    }
    throw error;
  }
};

