import { GoogleGenAI, Type } from "@google/genai";
import { Scene, StoryboardResponse } from "./types";

const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export const generateStoryboardData = async (story: string): Promise<StoryboardResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Act as a world-class Cinematic Visual Storyteller and Production Designer. 
    Your primary objective is to maintain ABSOLUTE CHARACTER CONSISTENCY while creating immersive, detailed environments.

    STEP 1: Define a "MASTER IDENTITY ANCHOR". 
    Create a 6-line technical visual description of the protagonist.
    - FACIAL TOPOLOGY: Exact bone structure, eye shape/color, nose profile, and jawline.
    - SKIN & DETAILS: Specific skin texture and unique identifiers.
    - COIFFURE: Exact hair length, texture, and styling.
    - WARDROBE: A signature outfit that remains constant across all beats.

    STEP 2: Analyze the story beats and mood: "${story}".

    STEP 3: For each scene, create a specific emotional micro-expression that modifies the MASTER IDENTITY.

    STEP 4: Environment Design. For each scene, define a rich background with specific props, atmospheric elements (fog, dust, rain), and thematic lighting that matches the story's "moodboard" topic.

    STEP 5: Output JSON. The "prompt" field for each scene MUST strictly follow this pattern:
    [MASTER IDENTITY ANCHOR] + [MICRO-EXPRESSION] + [DETAILED BACKGROUND DESCRIPTION WITH SPECIFIC THEMATIC ELEMENTS] + [CINEMATIC COMPOSITION & LIGHTING].

    Ensure every prompt contains a CLEAR background and the character is ALWAYS placed within that specific context.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          characterProfile: { 
            type: Type.STRING,
            description: "The technical 'Master Identity Anchor' for the character."
          },
          scenes: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                number: { type: Type.INTEGER },
                description: { type: Type.STRING },
                shotType: { type: Type.STRING },
                movement: { type: Type.STRING },
                lighting: { type: Type.STRING },
                tone: { type: Type.STRING },
                prompt: { 
                  type: Type.STRING,
                  description: "Full prompt: Master Identity + Expression + Detailed Background + Cinematic Specs."
                },
              },
              required: ["number", "description", "shotType", "movement", "lighting", "tone", "prompt"],
            },
          },
        },
        required: ["characterProfile", "scenes"],
      },
    },
  });

  const jsonStr = response.text.trim();
  return JSON.parse(jsonStr) as StoryboardResponse;
};

export const generateSceneImage = async (prompt: string, retries = 3): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const enhancedPrompt = `High-end cinematic film still, photorealistic, shot on 35mm Arri Alexa. 
  CHARACTER IDENTITY: Ensure the face is identical across frames. 
  SCENE CONTENT: ${prompt}. 
  WORLD BUILDING: Rich detailed background, specific environmental textures, realistic atmosphere (dust/smoke/moisture), Hollywood standard lighting, 8k, masterfully color graded, high production value.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: enhancedPrompt }],
      },
      config: {
        imageConfig: {
          aspectRatio: "16:9",
        },
      },
    });

    const part = response.candidates?.[0]?.content?.parts?.find(p => p.inlineData);
    if (part?.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
    throw new Error("No image data found in response");
  } catch (error: any) {
    if (retries > 0 && (error.message?.includes("429") || error.status === 429 || error.message?.includes("quota"))) {
      const waitTime = Math.pow(2, 4 - retries) * 2000;
      console.warn(`Quota exceeded. Retrying in ${waitTime}ms... (${retries} retries left)`);
      await delay(waitTime);
      return generateSceneImage(prompt, retries - 1);
    }
    throw error;
  }
};

