import React, { useState } from 'react';
import { Scene, AppStatus } from './types';
import { generateStoryboardData, generateSceneImage } from './geminiService';
import { SceneCard } from './components/SceneCard';
import { Film, Clapperboard, Sparkles, Send, Trash2, AlertCircle, User, Download, ShieldCheck, RefreshCw, Zap, Target, Lock } from 'lucide-react';

const App: React.FC = () => {
  const [story, setStory] = useState('');
  const [characterProfile, setCharacterProfile] = useState<string>('');
  const [scenes, setScenes] = useState<Scene[]>([]);
  const [images, setImages] = useState<Record<number, string>>({});
  const [status, setStatus] = useState<AppStatus>('idle');
  const [error, setError] = useState<string | null>(null);
  const [generatingImageIndices, setGeneratingImageIndices] = useState<Set<number>>(new Set());

  const handleGenerate = async () => {
    if (!story.trim()) return;

    setStatus('analyzing');
    setError(null);
    setScenes([]);
    setImages({});
    setCharacterProfile('');
    setGeneratingImageIndices(new Set());

    try {
      const data = await generateStoryboardData(story);
      setCharacterProfile(data.characterProfile);
      setScenes(data.scenes);
      setStatus('visualizing');

      for (const scene of data.scenes) {
        // Pacing requests for consistency focus
        if (scene.number > 1) {
          await new Promise(resolve => setTimeout(resolve, 3000));
        }

        setGeneratingImageIndices(prev => new Set(Array.from(prev).concat(scene.number)));
        try {
          const imageUrl = await generateSceneImage(scene.prompt);
          setImages(prev => ({ ...prev, [scene.number]: imageUrl }));
        } catch (imgErr: any) {
          console.error(`Failed to generate image for scene ${scene.number}`, imgErr);
        } finally {
          setGeneratingImageIndices(prev => {
            const next = new Set(prev);
            next.delete(scene.number);
            return next;
          });
        }
      }
      setStatus('completed');
    } catch (err: any) {
      console.error(err);
      setError(err.message || 'An error occurred during generation.');
      setStatus('error');
    }
  };

  const retryScene = async (scene: Scene) => {
    setGeneratingImageIndices(prev => new Set(Array.from(prev).concat(scene.number)));
    try {
      const imageUrl = await generateSceneImage(scene.prompt);
      setImages(prev => ({ ...prev, [scene.number]: imageUrl }));
    } catch (err) {
      console.error(`Retry failed for scene ${scene.number}`, err);
    } finally {
      setGeneratingImageIndices(prev => {
        const next = new Set(prev);
        next.delete(scene.number);
        return next;
      });
    }
  };

  const handleClear = () => {
    setStory('');
    setScenes([]);
    setImages({});
    setCharacterProfile('');
    setStatus('idle');
    setError(null);
  };

  const loadExample = () => {
    setStory("Detective Silas Thorne, age 45, with deep-set glacial blue eyes and high, sharp cheekbones. He has a thin, straight nose and a small jagged scar splitting his left eyebrow. His hair is a coarse iron-grey fade, swept back severely. He wears a heavy charcoal wool overcoat with a velvet collar. Scene 1: Silas stands in a smoky, rain-drenched jazz club, eyes scanning the crowd with focused intensity. Scene 2: He finds a blood-stained ledger hidden behind a piano, his face showing a subtle micro-expression of shock while maintaining his rigid facial structure. Scene 3: He runs out into the neon alley, shouting for a suspect, his face twisted in desperate determination, eyes wide but unmistakably Silas.");
  };

  const handleExport = () => {
    alert("Exporting cinematic sequence with absolute identity synchronization...");
  };

  return (
    <div className="min-h-screen flex flex-col pb-20 selection:bg-indigo-500/30">
      {/* Header */}
      <header className="sticky top-0 z-50 bg-slate-950/90 backdrop-blur-xl border-b border-slate-800/60">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-1.5 rounded-lg shadow-lg shadow-indigo-500/30">
              <Clapperboard className="w-5 h-5 text-white" />
            </div>
            <h1 className="text-xl font-bold tracking-tight text-white">SceneScribe <span className="text-indigo-400 font-light italic">Identity</span></h1>
          </div>

          <div className="hidden md:flex items-center gap-6 text-xs font-semibold text-slate-400 uppercase tracking-widest">
            <div className="flex items-center gap-2 text-emerald-400 bg-emerald-400/10 px-3 py-1.5 rounded-full border border-emerald-400/20">
              <Lock className="w-3.5 h-3.5 animate-pulse" />
              <span>100% Identity Lock</span>
            </div>
            <div className="flex items-center gap-2 text-indigo-400 bg-indigo-400/10 px-3 py-1.5 rounded-full border border-indigo-400/20">
              <Target className="w-3.5 h-3.5" />
              <span>Architectural Precision</span>
            </div>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-7xl mx-auto px-4 py-12 w-full">
        <div className="max-w-3xl mx-auto text-center mb-12">
          <h2 className="text-4xl md:text-5xl font-serif mb-4 text-white">Rigid Identity <span className="text-indigo-500 underline decoration-indigo-500/30 underline-offset-8">Sync</span></h2>
