        </div>

        {/* Story Input */}
        <div className="max-w-4xl mx-auto mb-16">
          <div className="bg-slate-900 border border-slate-800 rounded-2xl p-1 shadow-2xl transition-all focus-within:ring-2 focus-within:ring-indigo-500/30">
            <div className="relative">
              <textarea
                value={story}
                onChange={(e) => setStory(e.target.value)}
                placeholder="Describe your character's unique facial features and their journey..."
                className="w-full bg-slate-950 text-slate-100 border-0 rounded-xl p-6 min-h-[180px] focus:ring-0 resize-none placeholder:text-slate-700 text-lg leading-relaxed"
              />
              {status === 'idle' && story === '' && (
                <button 
                  onClick={loadExample}
                  className="absolute bottom-6 left-6 text-indigo-400 text-sm font-medium hover:text-indigo-300 transition-colors flex items-center gap-1.5 bg-indigo-950/30 px-3 py-1.5 rounded-lg border border-indigo-500/20"
                >
                  <Sparkles className="w-4 h-4" />
                  Try 'Silas Thorne: Identity Test'
