                  onClick={handleClear}
                  className="px-6 py-3 rounded-xl border border-slate-700 text-slate-400 hover:bg-slate-800 hover:text-slate-200 transition-all active:scale-95 flex items-center gap-2 flex-1 md:flex-initial justify-center"
                >
                  <Trash2 className="w-4 h-4" />
