                      <Zap className="w-4 h-4" />
                      Generate Sequence
                    </>
                  )}
                </button>
              </div>
            </div>
          </div>
        </div>

        {error && (
          <div className="max-w-4xl mx-auto mb-8 bg-rose-500/10 border border-rose-500/20 p-4 rounded-xl flex items-center gap-3 text-rose-400">
