export const generateSceneImage = async (prompt: string, retries = 3): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Professional Cinematography Injection for "Real Shot" look
  const enhancedPrompt = `A MASTERPIECE CINEMATIC PRODUCTION STILL, photorealistic, shot on Arri Alexa 65 with Cooke Anamorphic lenses. 
  CRITICAL: THE CHARACTER (FACE AND BODY) MUST BE 100% IDENTICAL TO PREVIOUS SHOTS. NO DEVIATION IN BONE STRUCTURE OR BUILD.
  ${prompt}. 
  Naturalistic skin textures, realistic subsurface scattering, eye moisture, anamorphic lens character, 8k, professional Hollywood lighting (rembrandt/chiaroscuro), masterfully color graded for high-end cinema, sharp focus, rich atmospheric detail, consistent actor identity.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: enhancedPrompt }],
      },
      config: {
        imageConfig: {
          aspectRatio: "16:9",
        },
      },
    });

    const part = response.candidates?.[0]?.content?.parts?.find(p => p.inlineData);
    if (part?.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
    throw new Error("No image data found in response");
  } catch (error: any) {
    if (retries > 0 && (error.message?.includes("429") || error.status === 429 || error.message?.includes("quota"))) {
      const waitTime = Math.pow(2, 4 - retries) * 2000;
      console.warn(`Quota exceeded. Retrying in ${waitTime}ms... (${retries} retries left)`);
      await delay(waitTime);
      return generateSceneImage(prompt, retries - 1);
    }
    throw error;
  }
};

