import { GoogleGenAI, Type } from "@google/genai";
import { Scene, StoryboardResponse } from "./types";

const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export const generateStoryboardData = async (story: string): Promise<StoryboardResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Act as a world-class Hollywood Cinematographer and Visual Concept Artist. 
    Your mission is to transform the provided story into a cinematic storyboard where every frame is a MASTERPIECE OF CONCEPTUAL STORYTELLING.

    STORY: "${story}"

    RULES FOR CONCEPTUAL INTEGRITY:
    1. MASTER IDENTITY: Define a technical 'Physical Identity Anchor' (Face and Body) that stays 100% consistent across all frames.
    2. CONCEPT FOCUS: For each scene, identify the 'CORE VISUAL CONCEPT' (the specific action, symbolism, or environment mentioned in the script). 
    3. NO HALLUCINATIONS: Do not add elements, characters, or props that are not explicitly stated or critically implied by the story beat.
    4. DIRECTORIAL PRECISION: Use specific shot types (Close-up, Wide, Dutch Angle) that best express the concept of that specific moment.

    STEP 1: Define the "MASTER IDENTITY TEMPLATE".
    Describe the character's face (bone structure, eyes, hair) and body (build, height) with technical precision.

    STEP 2: Create the Storyboard.
    For each scene, provide:
    - A technical prompt that starts with the SCENE CONCEPT and ACTION, then integrates the MASTER IDENTITY TEMPLATE.

    STEP 3: Output JSON. Ensure the "prompt" for each scene is a highly focused conceptual directive for an image generator.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          characterProfile: { 
            type: Type.STRING,
            description: "The technical 'Master Identity Template' (Face + Body)."
          },
          scenes: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                number: { type: Type.INTEGER },
                description: { type: Type.STRING },
                shotType: { type: Type.STRING },
                movement: { type: Type.STRING },
                lighting: { type: Type.STRING },
                tone: { type: Type.STRING },
                prompt: { 
                  type: Type.STRING,
                  description: "Hyper-focused conceptual prompt starting with the specific scene action/context."
                },
              },
              required: ["number", "description", "shotType", "movement", "lighting", "tone", "prompt"],
            },
          },
        },
        required: ["characterProfile", "scenes"],
      },
    },
  });

  const jsonStr = response.text.trim();
  return JSON.parse(jsonStr) as StoryboardResponse;
};

export const generateSceneImage = async (prompt: string, retries = 3): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Enhanced Conceptual Framing for Photorealistic Output
  const enhancedPrompt = `A HIGH-END CINEMATIC PRODUCTION STILL. 
  SCENE CONCEPT: ${prompt}. 
  CAMERA & LOOK: Shot on Arri Alexa 65, 35mm anamorphic lens, realistic depth of field. 
  CHARACTER CONSISTENCY: The person in the frame MUST match the identity description 100% in face, body build, and clothing.
  QUALITY SPECS: Photorealistic, natural skin textures, Hollywood lighting, masterfully color-graded, 8k resolution, authentic film look.
  STRICT ADHERENCE: Show ONLY the concepts and elements described. No extra background filler.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: enhancedPrompt }],
      },
      config: {
        imageConfig: {
          aspectRatio: "16:9",
        },
      },
    });

    const part = response.candidates?.[0]?.content?.parts?.find(p => p.inlineData);
    if (part?.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
    throw new Error("No image data found in response");
  } catch (error: any) {
    if (retries > 0 && (error.message?.includes("429") || error.status === 429 || error.message?.includes("quota"))) {
      const waitTime = Math.pow(2, 4 - retries) * 2000;
      console.warn(`Quota exceeded. Retrying in ${waitTime}ms... (${retries} retries left)`);
      await delay(waitTime);
      return generateSceneImage(prompt, retries - 1);
    }
    throw error;
  }
};

