import { GoogleGenAI, Type } from "@google/genai";
import { Scene, StoryboardResponse } from "./types";

const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export const generateStoryboardData = async (story: string): Promise<StoryboardResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Act as a world-class Hollywood Character Consistency Supervisor and Cinematographer. 
    Your absolute top priority is 100% CHARACTER IDENTITY LOCK (Face, Body, and Build) across all frames.

    STORY: "${story}"

    STEP 1: Define the "TECHNICAL IDENTITY SPECIFICATION" (TIS). 
    Create a highly detailed, non-ambiguous architectural profile of the character:
    - FACE: Specific bone structure (e.g., "high angular zygomatic arches", "square mandibular jawline"), eye shape and exact iris color, nose profile (e.g., "straight dorsum, slight alar flare"), and distinct skin texture/age.
    - BODY: Precise build and height (e.g., "Ectomorph build, 185cm tall, broad shoulders with long slender fingers").
    - WARDROBE: A fixed outfit that is described or inferred.

    STEP 2: Storyboard Generation.
    - Each frame MUST prioritize the TIS.
    - Use SOFT, BALANCED CINEMATIC LIGHTING. No harsh background glare or blown-out highlights.
    - Identify the 'CORE CONCEPT' of each beat from the story. 
    - NO HALLUCINATIONS: Do not add extra people or objects not in the script.

    STEP 3: Output JSON. The "prompt" field for each scene MUST strictly start with the verbatim TIS to ensure the image generator anchors the identity first.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          characterProfile: { 
            type: Type.STRING,
            description: "The technical TIS (Technical Identity Specification) for Face + Body consistency."
          },
          scenes: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                number: { type: Type.INTEGER },
                description: { type: Type.STRING },
                shotType: { type: Type.STRING },
                movement: { type: Type.STRING },
                lighting: { type: Type.STRING },
                tone: { type: Type.STRING },
                prompt: { 
                  type: Type.STRING,
                  description: "Final prompt: TIS + Scene Context + Soft Lighting directive."
                },
              },
              required: ["number", "description", "shotType", "movement", "lighting", "tone", "prompt"],
            },
          },
        },
        required: ["characterProfile", "scenes"],
      },
    },
  });

  const jsonStr = response.text.trim();
  return JSON.parse(jsonStr) as StoryboardResponse;
};

export const generateSceneImage = async (prompt: string, retries = 3): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Strict Identity Lock & Cinematic Quality Wrapper
