  ${prompt}. 
  [LIGHTING]: Soft cinematic lighting, Rembrandt shadows, naturalistic skin sub-surface scattering, no harsh background glare, no blown-out highlights.
  [STYLE]: Photorealistic, 8k, masterfully color-graded, authentic film grain, ultra-high fidelity, strict script adherence.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: enhancedPrompt }],
      },
      config: {
        imageConfig: {
          aspectRatio: "16:9",
        },
      },
    });

    const part = response.candidates?.[0]?.content?.parts?.find(p => p.inlineData);
    if (part?.inlineData) {
