export const generateSceneImage = async (prompt: string, retries = 3): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Hard Identity Anchor & Soft Lighting Wrapper
  const enhancedPrompt = `MASTERPIECE CINEMATIC PRODUCTION STILL, Arri Alexa 65, Anamorphic lens.
  [CRITICAL - IDENTITY LOCK]: This frame MUST feature the EXACT SAME character described below. 100% facial geometry match. 100% body build match. ZERO VARIATION.

  [CHARACTER DNA & SCENE]: ${prompt}

  [VISUAL STYLE]: Soft, cinematic, naturalistic lighting. NO harsh background glare. NO blown-out highlights. Soft Rembrandt shadows. 
  [QUALITY]: Photorealistic, 8k, authentic film grain, professional color grade, ultra-high fidelity, no extra elements.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: enhancedPrompt }],
      },
      config: {
        imageConfig: {
          aspectRatio: "16:9",
        },
      },
    });

    const part = response.candidates?.[0]?.content?.parts?.find(p => p.inlineData);
    if (part?.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
    throw new Error("No image data found in response");
  } catch (error: any) {
    if (retries > 0 && (error.message?.includes("429") || error.status === 429 || error.message?.includes("quota"))) {
      const waitTime = Math.pow(2, 4 - retries) * 2000;
      console.warn(`Quota exceeded. Retrying in ${waitTime}ms... (${retries} retries left)`);
      await delay(waitTime);
      return generateSceneImage(prompt, retries - 1);
    }
    throw error;
  }
};

